import { useState } from 'react'
import { motion } from 'framer-motion'
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts'
import Card from '../../components/ui/Card.tsx'
import Button from '../../components/ui/Button.tsx'
import Input from '../../components/ui/Input.tsx'
import type { WebhookEvent } from '../../types/api-developer.ts'
import {
  getApiKeys,
  createApiKey,
  revokeApiKey,
  regenerateApiKey,
  truncateKey,
  getWebhooks,
  createWebhook,
  toggleWebhook,
  deleteWebhook,
  getEndpoints,
  getCurlExample,
  getJsExample,
  getPythonExample,
  getUsageKPIs,
  getUsageHistory,
  getRateLimits,
  getWebhookEventLabel,
} from '../../services/api-developer.ts'

type Tab = 'docs' | 'keys' | 'webhooks' | 'usage'
type CodeLang = 'curl' | 'javascript' | 'python'

const ALL_EVENTS: WebhookEvent[] = [
  'audit.completed',
  'monitoring.scan_completed',
  'monitoring.alert',
  'credits.low',
  'citations.new',
]

function MethodBadge({ method }: { method: string }) {
  const colors: Record<string, string> = {
    GET: 'bg-green-100 text-green-700',
    POST: 'bg-blue-100 text-blue-700',
    PUT: 'bg-amber-100 text-amber-700',
    DELETE: 'bg-red-100 text-red-700',
  }
  return (
    <span className={`inline-block rounded px-2 py-0.5 text-xs font-bold ${colors[method] ?? 'bg-gray-100 text-gray-700'}`}>
      {method}
    </span>
  )
}

function CustomTooltip({ active, payload, label }: {
  active?: boolean
  payload?: Array<{ value: number; name: string; color: string }>
  label?: string
}) {
  if (!active || !payload) return null
  return (
    <div className="rounded-lg border border-gray-100 bg-white p-3 shadow-lg">
      <p className="mb-1 text-xs font-medium text-gray-500">{label}</p>
      {payload.map((entry) => (
        <p key={entry.name} className="text-sm" style={{ color: entry.color }}>
          {entry.name}: <span className="font-semibold">{entry.value}</span>
        </p>
      ))}
    </div>
  )
}

export default function ApiDeveloper() {
  const [activeTab, setActiveTab] = useState<Tab>('docs')
  const [expandedEndpoint, setExpandedEndpoint] = useState<string | null>(null)
  const [codeLang, setCodeLang] = useState<CodeLang>('curl')
  const [copiedText, setCopiedText] = useState<string | null>(null)

  // Keys state
  const [keys, setKeys] = useState(getApiKeys)
  const [newKeyName, setNewKeyName] = useState('')

  // Webhooks state
  const [webhooks, setWebhooks] = useState(getWebhooks)
  const [whUrl, setWhUrl] = useState('')
  const [whEvents, setWhEvents] = useState<WebhookEvent[]>([])

  const endpoints = getEndpoints()
  const rateLimits = getRateLimits()
  const usageKpis = getUsageKPIs()
  const usageHistory = getUsageHistory()

  function copyToClipboard(text: string, id: string) {
    navigator.clipboard.writeText(text)
    setCopiedText(id)
    setTimeout(() => setCopiedText(null), 2000)
  }

  function handleCreateKey() {
    if (!newKeyName.trim()) return
    createApiKey(newKeyName.trim())
    setKeys(getApiKeys())
    setNewKeyName('')
  }

  function handleRevokeKey(id: string) {
    revokeApiKey(id)
    setKeys(getApiKeys())
  }

  function handleRegenerateKey(id: string) {
    regenerateApiKey(id)
    setKeys(getApiKeys())
  }

  function handleCreateWebhook() {
    if (!whUrl.trim() || whEvents.length === 0) return
    createWebhook(whUrl.trim(), whEvents)
    setWebhooks(getWebhooks())
    setWhUrl('')
    setWhEvents([])
  }

  function handleToggleWebhook(id: string) {
    toggleWebhook(id)
    setWebhooks(getWebhooks())
  }

  function handleDeleteWebhook(id: string) {
    deleteWebhook(id)
    setWebhooks(getWebhooks())
  }

  function toggleEvent(event: WebhookEvent) {
    setWhEvents((prev) =>
      prev.includes(event) ? prev.filter((e) => e !== event) : [...prev, event]
    )
  }

  const tabs: { id: Tab; label: string }[] = [
    { id: 'docs', label: 'Documentation' },
    { id: 'keys', label: 'Cles API' },
    { id: 'webhooks', label: 'Webhooks' },
    { id: 'usage', label: 'Usage' },
  ]

  return (
    <div className="space-y-6">
      <h2 className="text-2xl font-bold text-gray-900">API Developer Hub</h2>

      {/* Tab Bar */}
      <div className="flex gap-1 rounded-lg bg-gray-100 p-1">
        {tabs.map((tab) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={`flex-1 rounded-md px-4 py-2 text-sm font-medium transition-colors ${
              activeTab === tab.id
                ? 'bg-white text-gray-900 shadow-sm'
                : 'text-gray-500 hover:text-gray-700'
            }`}
          >
            {tab.label}
          </button>
        ))}
      </div>

      {/* Documentation Tab */}
      {activeTab === 'docs' && (
        <motion.div className="space-y-4" initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
          {/* Rate Limits Banner */}
          <div className="flex flex-wrap items-center gap-4 rounded-xl bg-gradient-to-r from-blue-50 to-purple-50 p-4">
            <span className="text-sm font-medium text-gray-700">Rate limits :</span>
            {rateLimits.map((rl) => (
              <span key={rl.tier} className="rounded-full bg-white px-3 py-1 text-xs font-medium text-gray-700 shadow-sm">
                {rl.tier.charAt(0).toUpperCase() + rl.tier.slice(1)} : {rl.limit.toLocaleString('fr-FR')}/jour
              </span>
            ))}
          </div>

          {/* Code Language Selector */}
          <div className="flex gap-2">
            {(['curl', 'javascript', 'python'] as CodeLang[]).map((lang) => (
              <button
                key={lang}
                onClick={() => setCodeLang(lang)}
                className={`rounded-lg px-3 py-1.5 text-xs font-medium transition-colors ${
                  codeLang === lang ? 'bg-gray-900 text-white' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                }`}
              >
                {lang === 'curl' ? 'cURL' : lang === 'javascript' ? 'JavaScript' : 'Python'}
              </button>
            ))}
          </div>

          {/* Endpoints Accordion */}
          {endpoints.map((ep) => {
            const isOpen = expandedEndpoint === ep.path
            const codeExample = codeLang === 'curl' ? getCurlExample(ep) : codeLang === 'javascript' ? getJsExample(ep) : getPythonExample(ep)

            return (
              <Card key={ep.path} className="border border-gray-200">
                <button className="flex w-full items-center justify-between text-left" onClick={() => setExpandedEndpoint(isOpen ? null : ep.path)}>
                  <div className="flex items-center gap-3">
                    <MethodBadge method={ep.method} />
                    <code className="text-sm font-medium text-gray-900">{ep.path}</code>
                    {ep.gasCost > 0 && (
                      <span className="rounded-full bg-amber-100 px-2 py-0.5 text-xs text-amber-700">{ep.gasCost} Gas</span>
                    )}
                  </div>
                  <svg className={`h-5 w-5 text-gray-400 transition-transform ${isOpen ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                    <path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" />
                  </svg>
                </button>

                {isOpen && (
                  <motion.div className="mt-4 space-y-4" initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }}>
                    <p className="text-sm text-gray-600">{ep.description}</p>

                    {ep.params.length > 0 && (
                      <div className="overflow-x-auto">
                        <table className="w-full text-left text-sm">
                          <thead className="border-b border-gray-200 bg-gray-50">
                            <tr>
                              <th className="px-3 py-2 font-medium text-gray-600">Parametre</th>
                              <th className="px-3 py-2 font-medium text-gray-600">Type</th>
                              <th className="px-3 py-2 font-medium text-gray-600">Requis</th>
                              <th className="px-3 py-2 font-medium text-gray-600">Description</th>
                            </tr>
                          </thead>
                          <tbody className="divide-y divide-gray-100">
                            {ep.params.map((p) => (
                              <tr key={p.name}>
                                <td className="px-3 py-2"><code className="text-xs text-purple-600">{p.name}</code></td>
                                <td className="px-3 py-2 text-xs text-gray-500">{p.type}</td>
                                <td className="px-3 py-2">
                                  <span className={`text-xs font-medium ${p.required ? 'text-red-600' : 'text-gray-400'}`}>{p.required ? 'Oui' : 'Non'}</span>
                                </td>
                                <td className="px-3 py-2 text-xs text-gray-600">{p.description}</td>
                              </tr>
                            ))}
                          </tbody>
                        </table>
                      </div>
                    )}

                    <div className="relative">
                      <div className="flex items-center justify-between rounded-t-lg bg-gray-800 px-4 py-2">
                        <span className="text-xs text-gray-400">{codeLang === 'curl' ? 'cURL' : codeLang === 'javascript' ? 'JavaScript' : 'Python'}</span>
                        <button onClick={() => copyToClipboard(codeExample, `code_${ep.path}`)} className="text-xs text-gray-400 hover:text-white">
                          {copiedText === `code_${ep.path}` ? 'Copie !' : 'Copier'}
                        </button>
                      </div>
                      <pre className="overflow-x-auto rounded-b-lg bg-gray-900 p-4 text-xs text-green-400"><code>{codeExample}</code></pre>
                    </div>

                    <div>
                      <p className="mb-2 text-xs font-medium text-gray-500">Exemple de reponse :</p>
                      <pre className="overflow-x-auto rounded-lg bg-gray-50 p-4 text-xs text-gray-700"><code>{ep.exampleResponse}</code></pre>
                    </div>
                  </motion.div>
                )}
              </Card>
            )
          })}
        </motion.div>
      )}

      {/* Keys Tab */}
      {activeTab === 'keys' && (
        <motion.div className="space-y-4" initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
          <Card title="Nouvelle cle API">
            <div className="flex gap-3">
              <div className="flex-1">
                <Input label="Nom de la cle" placeholder="ex: Production, Staging..." value={newKeyName} onChange={(e) => setNewKeyName(e.target.value)} />
              </div>
              <div className="flex items-end">
                <Button onClick={handleCreateKey} disabled={!newKeyName.trim()}>Creer</Button>
              </div>
            </div>
          </Card>

          <Card title="Cles existantes">
            {keys.length === 0 ? (
              <p className="py-8 text-center text-sm text-gray-400">Aucune cle API creee</p>
            ) : (
              <div className="overflow-x-auto">
                <table className="w-full text-left text-sm">
                  <thead className="border-b border-gray-200 bg-gray-50">
                    <tr>
                      <th className="px-4 py-3 font-medium text-gray-600">Nom</th>
                      <th className="px-4 py-3 font-medium text-gray-600">Cle</th>
                      <th className="px-4 py-3 font-medium text-gray-600">Date</th>
                      <th className="px-4 py-3 font-medium text-gray-600">Statut</th>
                      <th className="px-4 py-3 font-medium text-gray-600">Actions</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-100">
                    {keys.map((k) => (
                      <tr key={k.id} className="hover:bg-gray-50">
                        <td className="px-4 py-3 font-medium text-gray-900">{k.name}</td>
                        <td className="px-4 py-3">
                          <div className="flex items-center gap-2">
                            <code className="text-xs text-gray-500">{truncateKey(k.key)}</code>
                            <button onClick={() => copyToClipboard(k.key, k.id)} className="text-xs text-blue-600 hover:text-blue-800">
                              {copiedText === k.id ? 'Copie !' : 'Copier'}
                            </button>
                          </div>
                        </td>
                        <td className="px-4 py-3 text-xs text-gray-500">{new Date(k.createdAt).toLocaleDateString('fr-FR')}</td>
                        <td className="px-4 py-3">
                          <span className={`inline-block rounded-full px-2 py-0.5 text-xs font-medium ${k.status === 'active' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                            {k.status === 'active' ? 'Active' : 'Revoquee'}
                          </span>
                        </td>
                        <td className="px-4 py-3">
                          <div className="flex gap-2">
                            {k.status === 'active' && (
                              <button onClick={() => handleRevokeKey(k.id)} className="text-xs text-red-600 hover:text-red-800">Revoquer</button>
                            )}
                            <button onClick={() => handleRegenerateKey(k.id)} className="text-xs text-blue-600 hover:text-blue-800">Regenerer</button>
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </Card>
        </motion.div>
      )}

      {/* Webhooks Tab */}
      {activeTab === 'webhooks' && (
        <motion.div className="space-y-4" initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
          <Card title="Ajouter un webhook">
            <div className="space-y-4">
              <Input label="URL du webhook" placeholder="https://votre-serveur.com/webhook" value={whUrl} onChange={(e) => setWhUrl(e.target.value)} />
              <div>
                <p className="mb-2 text-sm font-medium text-gray-700">Evenements</p>
                <div className="flex flex-wrap gap-2">
                  {ALL_EVENTS.map((event) => (
                    <button
                      key={event}
                      onClick={() => toggleEvent(event)}
                      className={`rounded-full px-3 py-1 text-xs font-medium transition-colors ${
                        whEvents.includes(event) ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                      }`}
                    >
                      {getWebhookEventLabel(event)}
                    </button>
                  ))}
                </div>
              </div>
              <Button onClick={handleCreateWebhook} disabled={!whUrl.trim() || whEvents.length === 0}>Ajouter le webhook</Button>
            </div>
          </Card>

          <Card title="Webhooks configures">
            {webhooks.length === 0 ? (
              <p className="py-8 text-center text-sm text-gray-400">Aucun webhook configure</p>
            ) : (
              <div className="space-y-3">
                {webhooks.map((wh) => (
                  <div key={wh.id} className="flex items-center justify-between rounded-lg border border-gray-200 p-4">
                    <div className="space-y-1">
                      <code className="text-sm text-gray-900">{wh.url}</code>
                      <div className="flex flex-wrap gap-1">
                        {wh.events.map((event) => (
                          <span key={event} className="rounded bg-gray-100 px-1.5 py-0.5 text-xs text-gray-600">{getWebhookEventLabel(event)}</span>
                        ))}
                      </div>
                      {wh.lastDelivery && (
                        <p className="text-xs text-gray-400">Derniere livraison : {new Date(wh.lastDelivery).toLocaleString('fr-FR')}</p>
