                    </div>
                    <div className="flex items-center gap-3">
                      <button
                        onClick={() => handleToggleWebhook(wh.id)}
                        className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${wh.active ? 'bg-blue-600' : 'bg-gray-300'}`}
                      >
                        <span className={`inline-block h-4 w-4 rounded-full bg-white transition-transform ${wh.active ? 'translate-x-6' : 'translate-x-1'}`} />
                      </button>
                      <button onClick={() => handleDeleteWebhook(wh.id)} className="text-xs text-red-600 hover:text-red-800">Supprimer</button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </Card>
        </motion.div>
      )}

      {/* Usage Tab */}
      {activeTab === 'usage' && (
        <motion.div className="space-y-4" initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
          <div className="grid grid-cols-1 gap-4 sm:grid-cols-3">
            <Card>
              <p className="text-sm text-gray-500">Requetes / jour</p>
              <p className="mt-1 text-2xl font-bold text-blue-600">{usageKpis.requestsPerDay}</p>
            </Card>
            <Card>
              <p className="text-sm text-gray-500">Taux d'erreur</p>
              <p className="mt-1 text-2xl font-bold text-red-600">{usageKpis.errorRate}%</p>
            </Card>
            <Card>
              <p className="text-sm text-gray-500">Latence moyenne</p>
              <p className="mt-1 text-2xl font-bold text-amber-600">{usageKpis.avgLatency} ms</p>
            </Card>
          </div>

          <Card title="Historique des 30 derniers jours">
            <div className="h-72">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={usageHistory} margin={{ top: 5, right: 10, left: -10, bottom: 0 }}>
                  <CartesianGrid strokeDasharray="3 3" stroke="#f1f5f9" />
                  <XAxis dataKey="date" tick={{ fontSize: 10, fill: '#94a3b8' }} tickLine={false} axisLine={{ stroke: '#e2e8f0' }} tickFormatter={(v: string) => v.slice(5)} />
                  <YAxis tick={{ fontSize: 11, fill: '#94a3b8' }} tickLine={false} axisLine={{ stroke: '#e2e8f0' }} />
                  <Tooltip content={<CustomTooltip />} />
                  <Bar dataKey="success" name="Succes" fill="#10B981" radius={[4, 4, 0, 0]} />
                  <Bar dataKey="errors" name="Erreurs" fill="#EF4444" radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </Card>

          <Card title="SDK officiels">
            <div className="grid grid-cols-1 gap-4 md:grid-cols-2">
              <div className="rounded-lg bg-gray-50 p-4">
                <div className="mb-2 flex items-center gap-2">
                  <span className="rounded bg-green-100 px-2 py-0.5 text-xs font-bold text-green-700">npm</span>
                  <span className="text-sm font-medium text-gray-900">Node.js / JavaScript</span>
                </div>
                <div className="flex items-center justify-between rounded-lg bg-gray-900 px-4 py-2">
                  <code className="text-sm text-green-400">npm install @citedby/sdk</code>
                  <button onClick={() => copyToClipboard('npm install @citedby/sdk', 'npm')} className="text-xs text-gray-400 hover:text-white">
                    {copiedText === 'npm' ? 'Copie !' : 'Copier'}
                  </button>
                </div>
              </div>
              <div className="rounded-lg bg-gray-50 p-4">
                <div className="mb-2 flex items-center gap-2">
                  <span className="rounded bg-blue-100 px-2 py-0.5 text-xs font-bold text-blue-700">pip</span>
                  <span className="text-sm font-medium text-gray-900">Python</span>
                </div>
                <div className="flex items-center justify-between rounded-lg bg-gray-900 px-4 py-2">
                  <code className="text-sm text-green-400">pip install citedby</code>
                  <button onClick={() => copyToClipboard('pip install citedby', 'pip')} className="text-xs text-gray-400 hover:text-white">
                    {copiedText === 'pip' ? 'Copie !' : 'Copier'}
                  </button>
                </div>
              </div>
            </div>
          </Card>
        </motion.div>
      )}
    </div>
  )
}
